const ALLOWED = [
  'order_index','name','asset_url','thumbnail_url','status','creative_direction','hide_creative_direction',
  'linear_issue_id','graphic_linear_issue_id','video_status','graphic_status','video_tweaks','graphic_tweaks',
  'client_video_approved_at','client_graphic_approved_at','kasper_approved_at','kasper_approved_by','kasper_seen',
  'kasper_approved_after_tweaks','kasper_finished_at','kasper_closed_at','thumb_rev','created_at',
];
const body = ($input.first() && $input.first().json && $input.first().json.body) || {};
const client = String(body.client || '').trim();
if (!client) throw new Error('client required');
const sample = body.sample || {};
let id = String(sample.id || '').trim();
if (!id) {
  id = 'sr_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2,8);
}
const row = { id, updated_at: new Date().toISOString() };
for (const k of ALLOWED) {
  if (Object.prototype.hasOwnProperty.call(sample, k)) {
    const v = sample[k];
    row[k] = v == null ? '' : String(v);
  }
}
const baseAt = String(body.comments_base_at || '');
return [{ json: { ...row, _client: client, _baseAt: baseAt } }];

const incoming = $('Build Row From Patch').first().json;
const existingArr = $('Read Existing Row').all();
const existing = (existingArr[0] && existingArr[0].json) || {};

// Read-failure guard: 'Read Existing Row' runs with onError: continueRegularOutput,
// so a Supabase API failure is forwarded as an item whose .error (object) /
// .json.error (string) is set instead of a real row. Return a clean, retryable
// {ok:false} via the no-write path (Is Conflict -> Respond JSON).
const _readItem = existingArr[0] || {};
if (_readItem.error || (_readItem.json && _readItem.json.error)) {
  return [{ json: { _conflict: true, ok: false, id: incoming.id,
    error: 'Not saved \u2014 the sample store was briefly unavailable. Your text is kept; please try again in a moment.' } }];
}

// Phantom-row guard.
const existsAlready = !!(existing && existing.id);
const CONTENT_FIELDS = ['name','asset_url','thumbnail_url','creative_direction','video_tweaks','graphic_tweaks'];
const hasAnyContent = CONTENT_FIELDS.some(k => String(incoming[k] == null ? '' : incoming[k]).trim() !== '');
if (!existsAlready && !hasAnyContent) {
  throw new Error('phantom-row guard: refusing to create sample_reviews row id ' + incoming.id + ' because the row does not exist and the payload contains no substantive content fields. This is the misrouted-skeleton pattern.');
}

const baseAt = String(incoming._baseAt || '');
const RETAIN_MS = 30*24*60*60*1000;
const nowMs = Date.now();
function parse(s){ try { const a = JSON.parse(s == null ? '[]' : (String(s) || '[]')); return Array.isArray(a) ? a.filter(c => c && c.id) : []; } catch (e) { return []; } }
function stamp(c){ return String((c && (c.updated_at || c.created_at)) || ''); }
function mergeCell(existingStr, incomingStr){
  const ex = parse(existingStr), inc = parse(incomingStr);
  const incIds = new Set(inc.map(c => c.id));
  const exById = new Map(ex.map(c => [c.id, c]));
  const out = [];
  for (const c of inc){ const e = exById.get(c.id); out.push(e && stamp(e) > stamp(c) ? e : c); }
  for (const e of ex){
    if (incIds.has(e.id)) continue;
    if (e.deleted) { out.push(e); continue; }
    const es = stamp(e);
    if (!baseAt) { out.push(e); continue; }
    if (es && es > baseAt) out.push(e);
  }
  const cutoff = nowMs - RETAIN_MS;
  const kept = out.filter(function(c){ if (!c.deleted) return true; const t = Date.parse(c.updated_at || c.created_at || ''); return !(isFinite(t) && t < cutoff); });
  return kept.length ? JSON.stringify(kept) : '';
}
const row = Object.assign({}, incoming);
for (const col of ['video_tweaks','graphic_tweaks']){
  if (Object.prototype.hasOwnProperty.call(incoming, col)) row[col] = mergeCell(existing[col], incoming[col]);
}

// Explicit link clear sentinel.
const CLEAR = '__CLEAR_LINK__';
const cleared = {};
for (const linkCol of ['graphic_linear_issue_id','linear_issue_id']){
  if (Object.prototype.hasOwnProperty.call(incoming, linkCol)
      && String(incoming[linkCol] == null ? '' : incoming[linkCol]).trim() === CLEAR) {
    row[linkCol] = '';
    cleared[linkCol] = true;
  }
}

// Link-clobber carry-forward guard.
for (const linkCol of ['graphic_linear_issue_id','linear_issue_id']){
  if (cleared[linkCol]) continue;
  if (Object.prototype.hasOwnProperty.call(incoming, linkCol)
      && String(incoming[linkCol] == null ? '' : incoming[linkCol]).trim() === ''
      && String(existing[linkCol] == null ? '' : existing[linkCol]).trim() !== '') {
    row[linkCol] = existing[linkCol];
  }
}

// comments_base_at conflict guard.
if (existsAlready && baseAt) {
  const storedAt = String(existing.updated_at || '');
  if (storedAt && storedAt > baseAt) {
    const SCALAR_FIELDS = ['name','asset_url','thumbnail_url','status','video_status','graphic_status','creative_direction','linear_issue_id','graphic_linear_issue_id','kasper_approved_at'];
    const changed = SCALAR_FIELDS.filter(k => Object.prototype.hasOwnProperty.call(incoming, k)
      && String(row[k] == null ? '' : row[k]) !== String(existing[k] == null ? '' : existing[k]));
    if (changed.length) {
      return [{ json: { _conflict: true, ok: false, conflict: true, id: incoming.id,
        error: 'Not saved: someone else updated this sample (' + changed.join(', ') + ') after your screen last loaded it. Refresh to see their version, then re-apply your change.' } }];
    }
  }
}

row._conflict = false;
return [{ json: row }];

const j = $input.item.json;
const out = {};
for (const k of Object.keys(j)) {
  if (k.charAt(0) === '_') continue;
  out[k] = j[k];
}
return { json: out };

const client = $('Build Row From Patch').first().json._client;
const src = $('Strip Routing').first().json || {};
const existingArr = $('Read Existing Row').all();
const existing = (existingArr[0] && existingArr[0].json) || {};
const existsAlready = !!(existing && existing.id);
const COLS = ['id','order_index','name','asset_url','thumbnail_url','status','creative_direction','hide_creative_direction','linear_issue_id','graphic_linear_issue_id','video_status','graphic_status','video_tweaks','graphic_tweaks','client_video_approved_at','client_graphic_approved_at','kasper_approved_at','kasper_approved_by','kasper_seen','kasper_approved_after_tweaks','kasper_finished_at','kasper_closed_at','thumb_rev','created_at','updated_at'];
const row = { client };
for (const k of COLS) { if (src[k] !== undefined) row[k] = src[k]; }
// Ensure every CREATE carries a created_at: when the row did not already exist
// and the patch sent no created_at, default it to this write's updated_at so a
// new row never has a null created_at. On an UPDATE we never write created_at
// unless the patch explicitly sent one (it is not in SCALAR_FIELDS), so the
// original created_at is preserved.
if (!existsAlready && (row.created_at === undefined || String(row.created_at || '').trim() === '')) {
  row.created_at = row.updated_at;
}
return [{ json: row }];

// Build the args for the atomic comment-merge RPC. Only include the *_tweaks
// columns actually in this save (others -> function default null = untouched).
const r = ($('Prep Mirror').first() && $('Prep Mirror').first().json) || {};
const args = { p_client: r.client, p_id: r.id, p_base: '' };
for (const c of ['video','graphic']) {
  const col = c + '_tweaks';
  if (Object.prototype.hasOwnProperty.call(r, col)) args['p_' + c] = (r[col] == null ? '' : String(r[col]));
}
return [{ json: args }];

// The atomic RPC already wrote the *_tweaks columns. The scalar mirror must NOT
// touch them (whole-cell write is the lost-update race), so drop them here.
const r = Object.assign({}, ($('Prep Mirror').first() && $('Prep Mirror').first().json) || {});
for (const k of ['video_tweaks','graphic_tweaks']) delete r[k];
return [{ json: r }];

// Diff incoming patch vs the Read-Existing-Row snapshot and emit one
// sample_review_events row per meaningful change. Best-effort.
const inc = ($('Strip Routing').first() && $('Strip Routing').first().json) || {};
const patch = ($('Build Row From Patch').first() && $('Build Row From Patch').first().json) || {};
const client = String(patch._client || '');
const existingArr = $('Read Existing Row').all();
const existing = (existingArr[0] && existingArr[0].json) || {};
const existsAlready = !!(existing && existing.id);
const sampleId = String(inc.id || patch.id || '');
const actor = String((patch && patch.kasper_approved_by) || '');
const nowIso = new Date().toISOString();
const has = (k) => Object.prototype.hasOwnProperty.call(patch, k);
const sv = (o,k) => String(o && o[k] == null ? '' : o[k]);
const events = [];
function ev(action, extra){
  events.push(Object.assign({ client, sample_id: sampleId, ts: nowIso, actor: actor || null, role: null, action, source: 'ui', created_at: nowIso }, extra || {}));
}

if (!existsAlready) {
  ev('create', { component: null, from_status: sv(existing,'status'), to_status: sv(inc,'status') || null });
} else {
  if (has('status') && sv(inc,'status') !== sv(existing,'status')) {
    if (String(sv(inc,'status')).toLowerCase() === 'archived') {
      ev('archive', { component: null, from_status: sv(existing,'status'), to_status: sv(inc,'status') });
    } else {
      ev('status_change', { component: null, from_status: sv(existing,'status'), to_status: sv(inc,'status') });
    }
  }
}
for (const comp of ['video','graphic']) {
  const col = comp + '_status';
  if (has(col) && sv(inc,col) !== sv(existing,col)) {
    ev('status_change', { component: comp, from_status: sv(existing,col), to_status: sv(inc,col) });
  }
}
if (has('client_video_approved_at') && sv(inc,'client_video_approved_at') && sv(inc,'client_video_approved_at') !== sv(existing,'client_video_approved_at')) {
  ev('approve_video', { component: 'video', role: 'client' });
}
if (has('client_graphic_approved_at') && sv(inc,'client_graphic_approved_at') && sv(inc,'client_graphic_approved_at') !== sv(existing,'client_graphic_approved_at')) {
  ev('approve_graphic', { component: 'graphic', role: 'client' });
}
if (has('kasper_approved_at') && sv(inc,'kasper_approved_at') && sv(inc,'kasper_approved_at') !== sv(existing,'kasper_approved_at')) {
  ev('kasper_approve', { component: null, role: 'kasper' });
}
if (has('kasper_finished_at') && sv(inc,'kasper_finished_at') && sv(inc,'kasper_finished_at') !== sv(existing,'kasper_finished_at')) {
  ev('kasper_finish', { component: null, role: 'kasper' });
}
if (has('kasper_closed_at') && sv(inc,'kasper_closed_at') && sv(inc,'kasper_closed_at') !== sv(existing,'kasper_closed_at')) {
  ev('kasper_close', { component: null, role: 'kasper' });
}
for (const pair of [['video','linear_issue_id'],['graphic','graphic_linear_issue_id']]) {
  const comp = pair[0], col = pair[1];
  if (!has(col)) continue;
  const before = sv(existing,col), after = sv(inc,col);
  if (after === before) continue;
  if (after && !before) ev('link_set', { component: comp, payload: { to: after } });
  else if (!after && before) ev('link_clear', { component: comp, payload: { from: before } });
  else ev('link_set', { component: comp, payload: { from: before, to: after } });
}
function ids(s){ try { const a = JSON.parse(s == null ? '[]' : (String(s) || '[]')); return Array.isArray(a) ? a.filter(c => c && c.id && !c.deleted).map(c => String(c.id)) : []; } catch(e){ return []; } }
for (const pair of [['video','video_tweaks'],['graphic','graphic_tweaks']]) {
  const comp = pair[0], col = pair[1];
  if (!has(col)) continue;
  const before = new Set(ids(existing[col]));
  const after = ids(inc[col]);
  const added = after.filter(x => !before.has(x));
  if (added.length) ev('comment_add', { component: comp, payload: { added } });
}

if (!events.length) return [];
return events.map(e => ({ json: e }));
